sys_ui_script.script:
window.amplitude.init('ac1e39e79d98cfb8d941900110e9f2f8', {
    autocapture: false,
    remoteConfig: false,
});

function createTracking(event, properties, enabled, categories) {
    var categoryEnabled = categories.indexOf(properties.category) != '-1';

    if (enabled) {
        if (categoryEnabled) {
            amplitude.track(event, properties);
        }
    }
}

function identifyUserTracking(userId) {
    // amplitude.setUserId();
}

function identifyPageTracking(page, category, enabled, categories) {
    var categoryEnabled = categories.indexOf(category) != '-1';
    if (enabled) {
        if (categoryEnabled) {
            let eventName = "Viewed " + page + " Page";
            let referrer = document.referrer;
            let path = location.pathname;
            let title = document.title;
            let url = location.href;
            let defaultProperties = {
                referrer,
                path,
                title,
                url
            };
            let properties = {
                name: page,
                ...defaultProperties
            };
            amplitude.track(eventName, properties);
            amplitude.track('Loaded a Page', properties);
        }
    }
}
